function techlead_web_page_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('techlead_web_page');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'techlead' => Request::val('techlead', 'GNSS Tech Lead'),
		'category' => Request::val('category', 'Foundational Research'),
		'author' => Request::val('author', ''),
		'content_title' => Request::val('content_title', ''),
		'content' => Request::val('content', ''),
		'content_learn_more' => Request::val('content_learn_more', ''),
		'img1' => Request::fileUpload('img1', [
			'maxSize' => 10240000,
			'types' => 'jpg|jpeg|gif|png|webp',
			'noRename' => false,
			'dir' => '',
			'success' => function($name, $selected_id) {
				Thumbnail::create($name, getThumbnailSpecs('techlead_web_page', 'img1', 'tv'));
			},
			'failure' => function($selected_id, $fileRemoved) {
				if(!strlen(Request::val('SelectedID'))) return '';

				/* for empty upload fields, when saving a copy of an existing record, copy the original upload field */
				return existing_value('techlead_web_page', 'img1', Request::val('SelectedID'));
			},
		]),
		'img2' => Request::fileUpload('img2', [
			'maxSize' => 10240000,
			'types' => 'jpg|jpeg|gif|png|webp',
			'noRename' => false,
			'dir' => '',
			'success' => function($name, $selected_id) {
				Thumbnail::create($name, getThumbnailSpecs('techlead_web_page', 'img2', 'tv'));
			},
			'failure' => function($selected_id, $fileRemoved) {
				if(!strlen(Request::val('SelectedID'))) return '';

				/* for empty upload fields, when saving a copy of an existing record, copy the original upload field */
				return existing_value('techlead_web_page', 'img2', Request::val('SelectedID'));
			},
		]),
		'approval_status' => Request::val('approval_status', 'Under Consideration'),
		'approval_remarks' => Request::val('approval_remarks', ''),
		'website_update_status' => Request::val('website_update_status', 'Pending'),
		'website_update_remarks' => Request::val('website_update_remarks', 'None'),
		'website_update_date' => Request::dateComponents('website_update_date', ''),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('techlead_web_page', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		techlead_web_page_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

